-- ========== Soluções (solutions-data.ts) — consumidas como "categorias" pelo frontend ==========
INSERT INTO solucoes (id, slug, titulo, icone, subtitulo_curto, descricao_curta, overview, features, imagem_url, fabricantes_titulo, fabricantes_descricao, ordem, ativo, categoria_id, created_at, updated_at)
VALUES
  (gen_random_uuid(), 'infraestrutura', 'Infraestrutura de TI Corporativa', 'server', 'Servidores robustos, redes resilientes e soluções de datacenter sob medida.', 'Sustente suas operações mais críticas com hardware de altíssima performance, escalabilidade nativa e arquitetura dedicada.', 'Nossa especialidade é projetar e implantar ambientes de hardware de alta densidade que não podem parar. Ajudamos empresas a dimensionar servidores locais e híbridos, otimizar roteamento de redes enterprise e gerenciar datacenters com foco em baixíssima latência e redundância física completa.', '[{"titulo":"Servidores Dedicados de Alta Densidade","descricao":"Processamento maciço com servidores de última geração (como Dell PowerEdge e Lenovo ThinkSystem), configurados sob medida para o ERP e bases de dados do seu negócio."},{"titulo":"Arquitetura de Rede Enterprise","descricao":"Switches de baixa latência, roteamento inteligente e firewalls integrados para garantir tráfego interno ultraveloz e seguro."},{"titulo":"Gestão e Sustentação Avançada","descricao":"Suporte especializado nível 3 constante, monitoramento de integridade física e substituição preventiva de componentes."}]'::jsonb, 'https://infodive.com.br/img/solucoes/infraestrutura.jpg', 'Fabricantes homologados', 'Trabalhamos com Dell Technologies, Lenovo e HPE.', 1, true, (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'armazenamento', 'Armazenamento & Storages Corporativos', 'hard-drive', 'Storage corporativo escalável, seguro e de ultra-performance.', 'Gerencie volumes massivos de dados com storages híbridos ou 100% Flash com taxas de transferência líderes de mercado.', 'Os dados são o ativo mais precioso das corporações. Projetamos sistemas de storage escaláveis (SAN, NAS e Object Storage) com deduplicação e compressão de hardware ativas, reduzindo o custo total de propriedade (TCO) enquanto entregamos os menores tempos de acesso possíveis.', '[{"titulo":"All-Flash & Storages Híbridos","descricao":"Aceleração de leitura e escrita com storages de alto desempenho para virtualização e analytics pesado."},{"titulo":"Tiering Inteligente & FinOps","descricao":"Movimentação automática de dados frios para camadas de armazenamento econômicas ou nuvem, otimizando o TCO."},{"titulo":"Deduplicação por Hardware","descricao":"Compactação em nível de bloco que maximiza o aproveitamento físico dos storages sem degradar a performance das aplicações."}]'::jsonb, 'https://infodive.com.br/img/solucoes/armazenamento.jpg', 'Fabricantes homologados', 'Trabalhamos com IBM, Dell Technologies e Lenovo.', 2, true, (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'protecao-de-dados', 'Proteção de Dados & Backup Imutável', 'shield-check', 'Sistemas avançados de backup, replicação e recuperação a prova de falhas.', 'Rotinas automáticas e criptografia militar para garantir que sua empresa possa restaurar operações críticas em minutos.', 'Protegemos a continuidade de negócios através de arquiteturas modernas de backup. Criamos ambientes imutáveis contra ataques de ransomware (WORM) e desenhamos estratégias de replicação geográfica e Disaster Recovery as a Service (DRaaS) com tempos de recuperação quase instantâneos.', '[{"titulo":"Backup Imutável (Anti-Ransomware)","descricao":"Gravação sob protocolo WORM (Write Once, Read Many). Mesmo se credenciais de administrador forem roubadas, o backup não pode ser apagado ou criptografado."},{"titulo":"Replicação Híbrida Automática","descricao":"Replicamos os dados no tripé local, nuvem privada Infodive e hiperescaladores em tempo real para total tolerância a desastres físicos."},{"titulo":"Orquestração de Desastres (DRaaS)","descricao":"Planos automatizados de contingência que sobem instâncias na nuvem em minutos, assumindo o processamento caso o datacenter local sofra uma parada total."}]'::jsonb, 'https://infodive.com.br/img/solucoes/protecao-de-dados.jpg', 'Fabricantes homologados', 'Trabalhamos com Veeam, Acronis e IBM.', 3, true, (SELECT id FROM categorias WHERE slug = 'backup-e-recuperacao'), now(), now()),
  (gen_random_uuid(), 'seguranca', 'Cibersegurança Ativa & Zero Trust', 'lock', 'Proteção ponta a ponta contra ameaças virtuais avançadas e conformidade LGPD.', 'Blindagem de perímetro, EDR/MDR proativos e gestão de acessos baseada no princípio do menor privilégio.', 'Nossa metodologia de segurança foca em inteligência de ameaças ativa e monitoramento contínuo. Implementamos políticas rígidas de Zero Trust, garantindo que todo dispositivo e usuário seja autenticado e monitorado ativamente antes de acessar dados críticos da organização.', '[{"titulo":"Zero Trust Network Access (ZTNA)","descricao":"Substituição de VPNs legadas por acessos granulares, contextualizados e seguros para cada colaborador, reduzindo drasticamente a superfície de ataque."},{"titulo":"EDR & MDR Avançados nos Endpoints","descricao":"Agentes inteligentes que detectam e bloqueiam comportamentos suspeitos e ameaças de dia zero em servidores e desktops em tempo real."},{"titulo":"Gestão e Proteção de Dados Sensíveis","descricao":"Descoberta, classificação automática e proteção ativa de dados confidenciais com soluções integradas como IBM Guardium."}]'::jsonb, 'https://infodive.com.br/img/solucoes/seguranca.jpg', 'Fabricantes homologados', 'Trabalhamos com IBM, Acronis e Microsoft.', 4, true, (SELECT id FROM categorias WHERE slug = 'seguranca'), now(), now()),
  (gen_random_uuid(), 'observability', 'Observability & Telemetria Enterprise', 'activity', 'Visão em tempo real da integridade das aplicações, redes e infraestrutura.', 'Métricas consolidadas, logs correlacionados e alertas inteligentes para detectar e mitigar problemas antes que afetem o cliente final.', 'Substituímos o monitoramento passivo por plataformas avançadas de observabilidade. Correlacionamos dados de performance de banco de dados, servidores, rede e experiência de usuário para gerar relatórios preditivos e automatizar a resolução de gargalos de software e hardware.', '[{"titulo":"Monitoramento APM e Infraestrutura","descricao":"Rastreamento completo do ciclo de requisições de software, latência de banco de dados e utilização de recursos físicos da infraestrutura."},{"titulo":"Correlação Inteligente de Logs","descricao":"Centralização e análise de logs com algoritmos avançados para identificar a causa raiz de anomalias em poucos segundos."},{"titulo":"Painéis Executivos & Técnicos","descricao":"Dashboards customizados que traduzem a saúde técnica dos sistemas em métricas e indicadores de negócios diretamente compreensíveis."}]'::jsonb, 'https://infodive.com.br/img/solucoes/observability.jpg', 'Fabricantes homologados', 'Trabalhamos com IBM, Microsoft e AWS.', 5, true, (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'virtualizacao', 'Virtualização & Consolidação de Servidores', 'layers', 'Hipervisores robustos para maximizar a eficiência energética e física.', 'Criação de clusters virtuais elásticos de alta densidade e isolamento de cargas com performance nativa.', 'Transformamos datacenters subutilizados em infraestruturas virtuais otimizadas. Gerenciamos e consolidamos ambientes físicos através de hipervisores modernos, maximizando o retorno de investimento (ROI) em computação e facilitando a recuperação em caso de falhas de hardware.', '[{"titulo":"Clusters de Alta Disponibilidade","descricao":"Agrupamento de múltiplos servidores físicos que realocam e iniciam workloads virtuais de forma automática caso algum nó apresente falhas."},{"titulo":"Live Migration Sem Interrupção","descricao":"Migração de sistemas ativos entre servidores físicos em tempo real para manutenções programadas, sem gerar impacto no uso."},{"titulo":"Hiperconvergência Eficiente","descricao":"Fusão lógica de processamento, armazenamento e redes em uma única camada virtualizada simplificada e inteligente."}]'::jsonb, 'https://infodive.com.br/img/solucoes/virtualizacao.jpg', 'Fabricantes homologados', 'Trabalhamos com VMware, Red Hat e Virtuozzo.', 6, true, (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'cloud', 'Nuvem Híbrida & Hiperescaladores', 'cloud', 'Arquitetura, migração segura e governança de cloud para alta escalabilidade.', 'Ambientes AWS, Azure ou nuvem privada Infodive integrados de forma transparente sob o conceito de nuvem híbrida.', 'Guiamos sua jornada para a nuvem de ponta a ponta. Seja migrando sistemas complexos para a AWS/Azure, operando nossa nuvem privada dedicada de alta performance ou integrando ambas em um ecossistema híbrido de latência ultra-baixa, estruturamos soluções seguras de acordo com regulamentações corporativas.', '[{"titulo":"Nuvem Híbrida Sob Medida","descricao":"Integração segura entre sua infraestrutura física (on-premises) e nuvens públicas, permitindo processamento elástico sem expor dados confidenciais."},{"titulo":"Governança Híbrida e Compliance","descricao":"Políticas de segurança centralizadas e controle de tráfego que evitam vazamentos e mantêm total conformidade legal."},{"titulo":"Otimização de Custos (FinOps)","descricao":"Monitoramento e redimensionamento constante de recursos em nuvem para eliminar desperdícios e manter as faturas previsíveis."}]'::jsonb, 'https://infodive.com.br/img/solucoes/cloud.jpg', 'Fabricantes homologados', 'Trabalhamos com AWS, Microsoft e Red Hat.', 7, true, (SELECT id FROM categorias WHERE slug = 'cloud'), now(), now()),
  (gen_random_uuid(), 'inteligencia-artificial', 'Infraestrutura para Inteligência Artificial', 'brain', 'Adoção prática, infraestrutura e plataformas especializadas para IA.', 'Desenvolvimento e sustentação de clusters para processamento massivo, modelagem de dados e IA Generativa aplicada.', 'Viabilizamos projetos de Inteligência Artificial desenhando a infraestrutura necessária. Desde o processamento de GPU de alto desempenho e pipelines de dados integrados até a implantação local ou híbrida de modelos de linguagem (LLMs) corporativos com privacidade total.', '[{"titulo":"Infraestrutura de Processamento para IA","descricao":"Configuração e entrega de servidores equipados com GPUs avançadas e arquitetura otimizada para treinamento e inferência de modelos analíticos."},{"titulo":"Plataformas de Modelagem e Dados","descricao":"Pipelines de dados modernos estruturados para alimentar modelos de machine learning de forma automatizada e com total integridade."},{"titulo":"Modelos Privativos (Local LLMs)","descricao":"Instalação de modelos de linguagem inteligência artificial em servidores próprios da empresa para análise de dados com garantia de sigilo industrial."}]'::jsonb, 'https://infodive.com.br/img/solucoes/inteligencia-artificial.jpg', 'Fabricantes homologados', 'Trabalhamos com IBM, Microsoft e AWS.', 8, true, (SELECT id FROM categorias WHERE slug = 'ia'), now(), now()),
  (gen_random_uuid(), 'endpoints', 'Endpoints & Gestão de Dispositivos', 'laptop', 'Gerenciamento centralizado, padronização e segurança de estações de trabalho.', 'Provisionamento automático, controle de patch management e segurança para frotas híbridas de desktops e notebooks.', 'Protegemos e padronizamos a porta de entrada da sua infraestrutura corporativa. Com soluções modernas de Unified Endpoint Management (UEM), mantemos servidores virtuais, notebooks de colaboradores e sistemas remotos constantemente atualizados, auditados e seguros.', '[{"titulo":"Unified Endpoint Management (UEM)","descricao":"Gerenciamento centralizado de sistemas operacionais híbridos (Windows, macOS, Linux) para auditorias de segurança e políticas unificadas."},{"titulo":"Distribuição e Patching Automático","descricao":"Atualizações de segurança críticas implantadas sem interrupção de produtividade dos colaboradores e com relatórios automáticos de conformidade."},{"titulo":"Segurança de Dispositivos Remotos","descricao":"Criptografia de disco local compulsória, bloqueio de portas USB e isolamento de máquinas perdidas ou roubadas para proteção total de informações corporativas."}]'::jsonb, 'https://infodive.com.br/img/solucoes/endpoints.jpg', 'Fabricantes homologados', 'Trabalhamos com Microsoft, Acronis e Apple.', 9, true, (SELECT id FROM categorias WHERE slug = 'seguranca'), now(), now())
ON CONFLICT (slug) DO NOTHING;

UPDATE solucoes
SET
  recurso_chave_1 = COALESCE(NULLIF(recurso_chave_1, ''), features->0->>'titulo'),
  recurso_chave_2 = COALESCE(NULLIF(recurso_chave_2, ''), features->1->>'titulo'),
  recurso_chave_3 = COALESCE(NULLIF(recurso_chave_3, ''), features->2->>'titulo')
WHERE features IS NOT NULL
  AND (
    recurso_chave_1 IS NULL OR recurso_chave_1 = ''
    OR recurso_chave_2 IS NULL OR recurso_chave_2 = ''
    OR recurso_chave_3 IS NULL OR recurso_chave_3 = ''
  );

-- ========== Junção N:N solucoes_fabricantes (vendors de cada solução) ==========
INSERT INTO solucoes_fabricantes (solucao_id, fabricante_id)
SELECT s.id, f.id
FROM solucoes s
JOIN fabricantes f ON
     (s.slug = 'infraestrutura'          AND f.slug IN ('dell', 'lenovo', 'hpe'))
  OR (s.slug = 'armazenamento'           AND f.slug IN ('ibm', 'dell', 'lenovo'))
  OR (s.slug = 'protecao-de-dados'       AND f.slug IN ('veeam', 'acronis', 'ibm'))
  OR (s.slug = 'seguranca'               AND f.slug IN ('ibm', 'acronis', 'microsoft'))
  OR (s.slug = 'observability'           AND f.slug IN ('ibm', 'microsoft', 'aws'))
  OR (s.slug = 'virtualizacao'           AND f.slug IN ('vmware', 'red-hat', 'virtuozzo'))
  OR (s.slug = 'cloud'                   AND f.slug IN ('aws', 'microsoft', 'red-hat'))
  OR (s.slug = 'inteligencia-artificial' AND f.slug IN ('ibm', 'microsoft', 'aws'))
  OR (s.slug = 'endpoints'               AND f.slug IN ('microsoft', 'acronis', 'apple'))
ON CONFLICT DO NOTHING;

