-- ========== Produtos (products-data.ts) — FKs resolvidas por slug ==========
INSERT INTO produtos (id, slug, nome, subcategoria, descricao_curta, descricao_completa, diferenciais, casos_de_uso, servicos_eyebrow, servicos_titulo, servicos_descricao, imagem_url, destaque, ativo, fabricante_id, solucao_id, categoria_id, created_at, updated_at)
VALUES
  (gen_random_uuid(), 'ibm-guardium', 'IBM Guardium', 'Segurança de Dados', 'Descoberta, monitoramento e proteção de dados sensíveis em tempo real.', 'O IBM Guardium oferece visibilidade total sobre onde estão seus dados sensíveis e quem os acessa. Monitora atividades em bancos de dados, data warehouses e ambientes de nuvem, aplicando políticas de conformidade (LGPD, PCI-DSS) e detectando comportamentos anômalos antes que virem incidentes.', '[{"titulo":"Descoberta automática","descricao":"Mapeia dados sensíveis em ambientes on-prem e multicloud sem agentes pesados."},{"titulo":"Análise de risco em tempo real","descricao":"Detecta acessos anômalos e tentativas de exfiltração com analytics comportamental."},{"titulo":"Conformidade contínua","descricao":"Relatórios prontos para LGPD, PCI-DSS, SOX e auditorias recorrentes."}]'::jsonb, '[{"titulo":"Proteção de dados regulados","descricao":"Instituições financeiras e saúde que precisam comprovar conformidade."},{"titulo":"Auditoria de acessos","descricao":"Rastreabilidade completa de quem acessou quais dados e quando."},{"titulo":"Resposta a incidentes","descricao":"Alertas acionáveis integrados ao SOC para conter ameaças rapidamente."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/ibm-guardium.jpg', true, true, (SELECT id FROM fabricantes WHERE slug = 'ibm'), (SELECT id FROM solucoes WHERE slug = 'seguranca'), (SELECT id FROM categorias WHERE slug = 'seguranca'), now(), now()),
  (gen_random_uuid(), 'veeam-data-platform', 'Veeam Data Platform', 'Backup & Recuperação', 'Backup e recuperação confiáveis para ambientes híbridos e multicloud.', 'A Veeam Data Platform unifica backup, recuperação e proteção contra ransomware em uma única plataforma. Com backups imutáveis, recuperação instantânea e verificação automática de restauração, garante a continuidade do negócio mesmo nos piores cenários.', '[{"titulo":"Backups imutáveis","descricao":"Cópias à prova de ransomware (WORM) que não podem ser alteradas ou apagadas."},{"titulo":"Recuperação instantânea","descricao":"Restaure VMs, bancos e arquivos em minutos, não em horas."},{"titulo":"Multicloud nativo","descricao":"Proteção consistente em VMware, Hyper-V, AWS, Azure e Microsoft 365."}]'::jsonb, '[{"titulo":"Defesa contra ransomware","descricao":"Camada imutável que garante recuperação sem pagar resgate."},{"titulo":"Disaster Recovery","descricao":"Failover orquestrado para um site secundário com RTO baixo."},{"titulo":"Proteção de Microsoft 365","descricao":"Backup de e-mails, Teams e SharePoint fora da retenção nativa."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/veeam-data-platform.jpg', true, true, (SELECT id FROM fabricantes WHERE slug = 'veeam'), (SELECT id FROM solucoes WHERE slug = 'protecao-de-dados'), (SELECT id FROM categorias WHERE slug = 'backup-e-recuperacao'), now(), now()),
  (gen_random_uuid(), 'dell-poweredge', 'Dell PowerEdge', 'Servidores', 'Servidores de alta performance para as cargas mais críticas do negócio.', 'Os servidores Dell PowerEdge entregam a base de computação para workloads exigentes — de virtualização densa a inteligência artificial. Com gerenciamento iDRAC, segurança em nível de hardware e escalabilidade modular, sustentam operações que não podem parar.', '[{"titulo":"Performance escalável","descricao":"Plataformas de 1 a 4 sockets para crescer conforme a demanda."},{"titulo":"Segurança no silício","descricao":"Root of Trust e boot verificado protegem desde o firmware."},{"titulo":"Gestão simplificada","descricao":"Automação de provisionamento e telemetria via iDRAC e OpenManage."}]'::jsonb, '[{"titulo":"Virtualização densa","descricao":"Consolide dezenas de VMs por host com alta disponibilidade."},{"titulo":"Cargas de IA/ML","descricao":"Configurações com GPU para treinamento e inferência."},{"titulo":"Edge computing","descricao":"Modelos compactos para filiais e ambientes de borda."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/dell-poweredge.jpg', false, true, (SELECT id FROM fabricantes WHERE slug = 'dell'), (SELECT id FROM solucoes WHERE slug = 'infraestrutura'), (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'acronis-cyber-protect', 'Acronis Cyber Protect', 'Backup & Cibersegurança', 'Cibersegurança e backup unificados em uma única solução integrada.', 'O Acronis Cyber Protect combina backup, anti-malware com IA e gestão de proteção numa só plataforma. Reduz a complexidade de operar ferramentas separadas e garante que os dados estejam protegidos e recuperáveis mesmo sob ataque ativo.', '[{"titulo":"Proteção unificada","descricao":"Backup e EDR no mesmo agente, sem conflitos entre ferramentas."},{"titulo":"Anti-ransomware com IA","descricao":"Detecção comportamental que reverte alterações maliciosas."},{"titulo":"Gestão centralizada","descricao":"Console único para políticas, alertas e recuperação."}]'::jsonb, '[{"titulo":"PMEs e filiais","descricao":"Proteção completa sem time de segurança dedicado."},{"titulo":"Endpoints remotos","descricao":"Backup e defesa de notebooks fora da rede corporativa."},{"titulo":"Recuperação confiável","descricao":"Restauração validada após incidentes de segurança."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/acronis-cyber-protect.jpg', false, true, (SELECT id FROM fabricantes WHERE slug = 'acronis'), (SELECT id FROM solucoes WHERE slug = 'seguranca'), (SELECT id FROM categorias WHERE slug = 'seguranca'), now(), now()),
  (gen_random_uuid(), 'red-hat-openshift', 'Red Hat OpenShift', 'Kubernetes & Containers', 'Plataforma Kubernetes corporativa para nuvem pública, privada e híbrida.', 'O Red Hat OpenShift é a plataforma de containers líder para modernizar aplicações e padronizar a entrega de software. Oferece Kubernetes endurecido, pipelines de CI/CD integrados e operação consistente em qualquer nuvem ou datacenter.', '[{"titulo":"Híbrido de verdade","descricao":"Mesma experiência on-prem, em nuvem pública e na borda."},{"titulo":"Segurança integrada","descricao":"Políticas, RBAC e supply chain seguro por padrão."},{"titulo":"Produtividade dev","descricao":"CI/CD, GitOps e catálogos de serviços prontos para times."}]'::jsonb, '[{"titulo":"Modernização de apps","descricao":"Migre monólitos para microsserviços com containers."},{"titulo":"Plataforma interna","descricao":"Self-service para times de desenvolvimento (IDP)."},{"titulo":"Workloads de IA","descricao":"Orquestração de modelos e pipelines de dados em escala."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/red-hat-openshift.jpg', true, true, (SELECT id FROM fabricantes WHERE slug = 'red-hat'), (SELECT id FROM solucoes WHERE slug = 'cloud'), (SELECT id FROM categorias WHERE slug = 'cloud'), now(), now()),
  (gen_random_uuid(), 'microsoft-azure', 'Microsoft Azure', 'Nuvem Pública', 'Nuvem escalável para modernização, inovação e analytics em escala global.', 'A nuvem Microsoft Azure oferece um catálogo completo de serviços — computação, dados, IA e segurança — com presença global. A Infodive projeta, migra e gerencia ambientes Azure com governança de custos (FinOps) e segurança Zero Trust.', '[{"titulo":"Escala global","descricao":"Datacenters em dezenas de regiões com baixa latência."},{"titulo":"IA e dados","descricao":"Serviços gerenciados de IA, analytics e bancos de dados."},{"titulo":"Governança de custos","descricao":"FinOps e tags para previsibilidade e otimização contínua."}]'::jsonb, '[{"titulo":"Migração para a nuvem","descricao":"Lift-and-shift ou modernização de cargas legadas."},{"titulo":"Ambientes híbridos","descricao":"Integração com datacenter via Azure Arc e ExpressRoute."},{"titulo":"Plataformas de dados","descricao":"Lakehouse e analytics com Synapse e Fabric."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/microsoft-azure.jpg', false, true, (SELECT id FROM fabricantes WHERE slug = 'microsoft'), (SELECT id FROM solucoes WHERE slug = 'cloud'), (SELECT id FROM categorias WHERE slug = 'cloud'), now(), now()),
  (gen_random_uuid(), 'ibm-flashsystem', 'IBM FlashSystem', 'Storage All-Flash', 'Armazenamento all-flash de alta performance com proteção contra ransomware.', 'O IBM FlashSystem entrega latência consistente em microssegundos com eficiência de dados por hardware (compressão e deduplicação). Inclui Safeguarded Copies imutáveis e detecção de anomalias por IA, unindo performance e resiliência cibernética no storage.', '[{"titulo":"Latência previsível","descricao":"Resposta em microssegundos mesmo sob carga intensa."},{"titulo":"Eficiência por hardware","descricao":"Compressão e dedup sem impacto na performance."},{"titulo":"Resiliência cibernética","descricao":"Cópias imutáveis e detecção de ransomware no storage."}]'::jsonb, '[{"titulo":"Bancos de dados críticos","descricao":"Workloads transacionais que exigem baixa latência."},{"titulo":"Consolidação de storage","descricao":"Reduza TCO unificando cargas em uma plataforma."},{"titulo":"Proteção de dados primários","descricao":"Recuperação rápida a partir de cópias imutáveis."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/ibm-flashsystem.jpg', false, true, (SELECT id FROM fabricantes WHERE slug = 'ibm'), (SELECT id FROM solucoes WHERE slug = 'armazenamento'), (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now()),
  (gen_random_uuid(), 'lenovo-thinkagile', 'Lenovo ThinkAgile', 'Hiperconvergência (HCI)', 'Infraestrutura hiperconvergente que simplifica datacenter e filiais.', 'As plataformas Lenovo ThinkAgile integram computação, armazenamento e rede em appliances hiperconvergentes pré-validados. Reduzem a complexidade do datacenter, aceleram a implantação e escalam de forma linear conforme o negócio cresce.', '[{"titulo":"Implantação acelerada","descricao":"Appliances pré-validados prontos para produção em horas."},{"titulo":"Escala linear","descricao":"Adicione nós sem rearquitetar o ambiente."},{"titulo":"Operação simplificada","descricao":"Gestão unificada de compute, storage e rede."}]'::jsonb, '[{"titulo":"Modernização de datacenter","descricao":"Substitua silos por uma stack convergente."},{"titulo":"VDI","descricao":"Desktops virtuais com performance previsível."},{"titulo":"Filiais (ROBO)","descricao":"Infraestrutura compacta e gerenciada remotamente."}]'::jsonb, 'Integra com nossos serviços', 'Do projeto à operação', 'Implementamos, migramos e sustentamos sua plataforma de ponta a ponta.', 'https://infodive.com.br/img/produtos/lenovo-thinkagile.jpg', false, true, (SELECT id FROM fabricantes WHERE slug = 'lenovo'), (SELECT id FROM solucoes WHERE slug = 'virtualizacao'), (SELECT id FROM categorias WHERE slug = 'infraestrutura'), now(), now())
ON CONFLICT (slug) DO NOTHING;

-- ========== Junção N:N produto_servico (serviços que cada produto integra) ==========
INSERT INTO produto_servico (produto_id, servico_id)
SELECT p.id, s.id
FROM produtos p
JOIN servicos s ON
     (p.slug = 'ibm-guardium'          AND s.slug IN ('implementacao', 'sustentacao-24-7', 'conformidade'))
  OR (p.slug = 'veeam-data-platform'   AND s.slug IN ('implementacao', 'draas', 'sustentacao-24-7'))
  OR (p.slug = 'dell-poweredge'        AND s.slug IN ('projeto-deploy', 'sustentacao-24-7', 'monitoramento'))
  OR (p.slug = 'acronis-cyber-protect' AND s.slug IN ('implementacao', 'sustentacao-24-7', 'monitoramento'))
  OR (p.slug = 'red-hat-openshift'     AND s.slug IN ('arquitetura', 'migracao', 'sustentacao-24-7'))
  OR (p.slug = 'microsoft-azure'       AND s.slug IN ('migracao', 'cloud-gerenciada', 'sustentacao-24-7'))
  OR (p.slug = 'ibm-flashsystem'       AND s.slug IN ('projeto-deploy', 'sustentacao-24-7', 'monitoramento'))
  OR (p.slug = 'lenovo-thinkagile'     AND s.slug IN ('projeto-deploy', 'migracao', 'sustentacao-24-7'))
ON CONFLICT DO NOTHING;

-- ========== Conteúdos / Blog (blog-data.ts) — categoria_id e fabricante_id resolvidos por slug ==========
INSERT INTO conteudos (id, titulo, slug, tipo, origem, descricao, conteudo, imagem_url, url_externa, social_post_id, autor, tempo_leitura, publicado_em, ativo, destaque, categoria_id, fabricante_id, produto_id, created_at, updated_at)
VALUES
  (gen_random_uuid(), 'Como o IBM Guardium protege dados sensíveis em ambientes híbridos', 'ibm-guardium-dados-sensiveis-ambientes-hibridos', 'ARTIGO', 'INTERNO', 'Entenda como implementar conformidade LGPD sem impactar a performance do ambiente.', '[{"tipo":"paragrafo","texto":"Proteger dados sensíveis deixou de ser uma preocupação restrita ao time de segurança e passou a ser tema de conselho. Com a LGPD, qualquer vazamento envolvendo dados pessoais expõe a empresa a multas, danos reputacionais e perda de confiança do cliente. O desafio cresce em ambientes híbridos, onde a informação transita entre datacenter, nuvem pública e SaaS."},{"tipo":"subtitulo","texto":"Visibilidade antes de controle"},{"tipo":"paragrafo","texto":"Não se protege o que não se enxerga. O IBM Guardium começa pela descoberta e classificação automática de dados sensíveis espalhados pelos repositórios — bancos relacionais, NoSQL, data lakes e arquivos. A partir desse mapa, é possível definir políticas de acesso e monitoramento com base no risco real de cada ativo."},{"tipo":"subtitulo","texto":"Monitoração contínua sem penalizar a performance"},{"tipo":"paragrafo","texto":"A maior objeção dos DBAs costuma ser o impacto na performance. O Guardium opera com agentes leves (S-TAPs) que interceptam o tráfego de banco fora do caminho crítico da transação, registrando quem acessou o quê, quando e de onde — sem adicionar latência perceptível à aplicação."},{"tipo":"lista","itens":["Auditoria independente do DBA, separando funções e evitando conflito de interesse.","Alertas em tempo real para acessos anômalos ou exfiltração de dados.","Mascaramento dinâmico para ambientes de homologação e desenvolvimento.","Relatórios prontos para auditorias de LGPD, PCI-DSS e ISO 27001."]},{"tipo":"citacao","texto":"Conformidade não é um projeto com data de término — é um processo contínuo de visibilidade, controle e evidência."},{"tipo":"subtitulo","texto":"Como a Infodive conduz o projeto"},{"tipo":"paragrafo","texto":"Implantamos o Guardium em fases: começamos por um assessment dos repositórios críticos, definimos as políticas junto ao time de dados e ativamos a monitoração em modo observação antes de aplicar bloqueios. Esse método reduz falsos positivos e garante adoção sem fricção com as áreas de negócio."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '7 min de leitura', '2026-05-18 10:00:00', true, true, (SELECT id FROM solucoes WHERE slug = 'seguranca'), (SELECT id FROM fabricantes WHERE slug = 'ibm'), NULL, now(), now()),
  (gen_random_uuid(), 'Guia completo de recuperação de desastres com Veeam Data Platform', 'recuperacao-de-desastres-veeam-data-platform', 'WHITEPAPER', 'INTERNO', 'Estratégias práticas para atingir RTO abaixo de 4 horas em ambientes críticos.', '[{"tipo":"paragrafo","texto":"Um plano de recuperação de desastres só vale o que entrega quando testado sob pressão. Ter backup não é o mesmo que ter capacidade de recuperação. Este guia apresenta a abordagem que usamos para desenhar estratégias de DR com objetivos de RTO e RPO realistas e mensuráveis."},{"tipo":"subtitulo","texto":"RTO e RPO: traduzindo risco em números"},{"tipo":"paragrafo","texto":"Antes de escolher tecnologia, é preciso classificar as aplicações por criticidade de negócio. Sistemas que sustentam faturamento exigem RTO de minutos; um portal interno tolera horas. Esse mapeamento define onde investir em replicação contínua e onde o backup tradicional já é suficiente."},{"tipo":"subtitulo","texto":"Backup imutável contra ransomware"},{"tipo":"paragrafo","texto":"Ransomware moderno busca apagar ou criptografar os backups antes de atacar a produção. Com repositórios imutáveis (hardened repository e object lock), o Veeam garante cópias que não podem ser alteradas nem excluídas durante o período definido — sua última linha de defesa."},{"tipo":"lista","itens":["Regra 3-2-1-1-0: três cópias, dois meios, uma off-site, uma imutável, zero erros nos testes.","Replicação para site secundário ou nuvem com failover orquestrado.","Instant Recovery para subir VMs direto do backup em minutos.","SureBackup: testes automáticos de restauração validando o plano de DR."]},{"tipo":"citacao","texto":"Um backup que nunca foi testado é apenas uma esperança. DR de verdade se prova com ensaios periódicos."},{"tipo":"subtitulo","texto":"Atingindo RTO abaixo de 4 horas"},{"tipo":"paragrafo","texto":"Combinando Instant Recovery, replicação e runbooks de failover documentados, ambientes críticos atingem RTO inferior a quatro horas de forma consistente. A Infodive entrega o plano, automatiza os testes e acompanha os ensaios trimestrais junto ao cliente."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '9 min de leitura', '2026-05-10 10:00:00', true, true, (SELECT id FROM solucoes WHERE slug = 'protecao-de-dados'), (SELECT id FROM fabricantes WHERE slug = 'veeam'), NULL, now(), now()),
  (gen_random_uuid(), 'Como reduzimos 40% dos custos de cloud de uma fintech em 3 meses', 'reducao-de-custos-cloud-fintech', 'CASE', 'INTERNO', 'Da auditoria ao FinOps: o processo que a Infodive usou para recuperar controle do budget.', '[{"tipo":"paragrafo","texto":"Uma fintech em crescimento acelerado nos procurou com um problema comum: a conta de cloud crescia mais rápido que a receita, sem que ninguém soubesse exatamente o porquê. Em 90 dias, reduzimos 40% do custo mensal sem comprometer performance nem disponibilidade."},{"tipo":"subtitulo","texto":"O diagnóstico: para onde o dinheiro estava indo"},{"tipo":"paragrafo","texto":"A primeira etapa foi tornar o gasto visível. Mapeamos recursos por aplicação, ambiente e time, e descobrimos os suspeitos de sempre: máquinas superdimensionadas, ambientes de teste ligados 24/7, discos órfãos e ausência total de reservas de capacidade."},{"tipo":"lista","itens":["Rightsizing de VMs com base em telemetria real de CPU e memória.","Desligamento automático de ambientes de não-produção fora do horário comercial.","Reserved Instances e Savings Plans para workloads previsíveis.","Limpeza de discos, snapshots e IPs órfãos sem uso."]},{"tipo":"subtitulo","texto":"De economia pontual a cultura de FinOps"},{"tipo":"paragrafo","texto":"Cortar custo uma vez é fácil; manter o controle é o desafio. Implantamos um ciclo de FinOps com dashboards de custo por time, alertas de anomalia e revisões mensais. A engenharia passou a enxergar o impacto financeiro de cada decisão de arquitetura."},{"tipo":"citacao","texto":"Cloud sem governança é dinheiro jogado fora. FinOps transforma custo em uma métrica de engenharia, não só de finanças."},{"tipo":"paragrafo","texto":"Três meses depois, além dos 40% de redução, a fintech ganhou previsibilidade de budget e passou a tratar eficiência de nuvem como parte do processo de desenvolvimento."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '6 min de leitura', '2026-05-02 10:00:00', true, true, (SELECT id FROM solucoes WHERE slug = 'cloud'), (SELECT id FROM fabricantes WHERE slug = 'microsoft'), NULL, now(), now()),
  (gen_random_uuid(), 'VMware vs Proxmox: qual escolher para modernizar seu datacenter?', 'vmware-vs-proxmox-modernizar-datacenter', 'ARTIGO', 'INTERNO', 'Análise técnica e comercial das duas plataformas mais usadas em virtualização enterprise.', '[{"tipo":"paragrafo","texto":"As mudanças de licenciamento dos últimos anos reacenderam uma pergunta nas reuniões de TI: continuar no VMware ou migrar para Proxmox? Não existe resposta universal — existe a resposta certa para o seu contexto. Vamos comparar as duas plataformas com honestidade técnica e comercial."},{"tipo":"subtitulo","texto":"Maturidade e ecossistema"},{"tipo":"paragrafo","texto":"O VMware oferece um ecossistema maduro, suporte enterprise robusto e integração nativa com praticamente todo fabricante de storage e backup. É a escolha segura para ambientes de missão crítica com requisitos rígidos de SLA e compliance."},{"tipo":"subtitulo","texto":"Custo e flexibilidade"},{"tipo":"paragrafo","texto":"O Proxmox, open source e baseado em KVM e LXC, elimina o custo de licença e entrega excelente performance. Em troca, exige mais maturidade da equipe interna e um parceiro técnico sólido para arquitetura, alta disponibilidade e suporte."},{"tipo":"lista","itens":["Workloads críticos com forte exigência de SLA tendem a permanecer no VMware.","Ambientes de desenvolvimento, laboratório e cargas elásticas se beneficiam do Proxmox.","Cenários híbridos — VMware na produção, Proxmox no resto — são cada vez mais comuns.","O custo total deve considerar licença, suporte, capacitação e risco operacional."]},{"tipo":"citacao","texto":"A pergunta certa não é ''qual é melhor?'', mas ''qual entrega o melhor resultado para a minha operação e a minha equipe?''."},{"tipo":"paragrafo","texto":"A Infodive conduz provas de conceito com os dois hypervisors e apresenta uma análise de TCO de três anos, para que a decisão seja baseada em dados — não em modismo."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '8 min de leitura', '2026-04-28 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'virtualizacao'), (SELECT id FROM fabricantes WHERE slug = 'vmware'), NULL, now(), now()),
  (gen_random_uuid(), 'Datasheet: Servidores ThinkSystem SR650 V3', 'datasheet-lenovo-thinksystem-sr650-v3', 'DATASHEET', 'INTERNO', 'Especificações técnicas, configurações disponíveis e casos de uso recomendados.', '[{"tipo":"paragrafo","texto":"O Lenovo ThinkSystem SR650 V3 é um servidor rack 2U de duplo socket projetado para o coração do datacenter corporativo: virtualização, bancos de dados, cargas de IA e ambientes de uso geral que exigem desempenho e densidade."},{"tipo":"subtitulo","texto":"Especificações principais"},{"tipo":"lista","itens":["Processadores Intel Xeon Scalable de 5ª geração, até 64 núcleos por socket.","Até 8 TB de memória DDR5 em 32 slots, com suporte a ECC.","Até 20 baias NVMe/SAS/SATA para flexibilidade de armazenamento.","Slots PCIe Gen5 para aceleradores GPU e adaptadores de alta velocidade.","Fontes redundantes Titanium e refrigeração otimizada para eficiência energética."]},{"tipo":"subtitulo","texto":"Casos de uso recomendados"},{"tipo":"paragrafo","texto":"O SR650 V3 é a base ideal para clusters de virtualização VMware ou Proxmox, infraestrutura hiperconvergente, bancos de dados transacionais e inferência de IA. Sua densidade de memória e expansão NVMe atendem desde consolidação até workloads de alta performance."},{"tipo":"citacao","texto":"Dimensionar corretamente o servidor na origem evita gargalos caros — e retrabalho — no futuro."},{"tipo":"paragrafo","texto":"A Infodive ajuda a configurar o SR650 V3 sob medida para o seu workload, com homologação de fábrica e suporte local. Solicite a configuração ideal para o seu projeto."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '4 min de leitura', '2026-04-22 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'infraestrutura'), (SELECT id FROM fabricantes WHERE slug = 'lenovo'), NULL, now(), now()),
  (gen_random_uuid(), 'Proteção contra ransomware em rede hospitalar com Acronis Cyber Protect', 'ransomware-rede-hospitalar-acronis-cyber-protect', 'CASE', 'INTERNO', 'Como implementamos backup imutável e detecção de comportamento em 72 horas.', '[{"tipo":"paragrafo","texto":"Em ambientes de saúde, indisponibilidade não é só prejuízo financeiro — é risco à vida. Uma rede hospitalar nos acionou após um incidente de ransomware no setor, buscando blindar sua operação rapidamente. Em 72 horas, colocamos em pé uma camada de proteção e recuperação confiável."},{"tipo":"subtitulo","texto":"O contexto: alto risco, baixa tolerância a downtime"},{"tipo":"paragrafo","texto":"Sistemas de prontuário eletrônico, PACS de imagens e integrações com laboratório precisam estar disponíveis 24/7. Qualquer parada afeta atendimento. Era preciso uma solução que unisse backup, antimalware e detecção comportamental sem multiplicar consoles."},{"tipo":"subtitulo","texto":"A implementação em 72 horas"},{"tipo":"lista","itens":["Backup imutável local e em nuvem, protegido contra exclusão.","Detecção comportamental de ransomware com reversão automática de arquivos.","Política de proteção unificada para servidores, endpoints e cargas virtualizadas.","Testes de restauração validando o RTO dos sistemas críticos."]},{"tipo":"citacao","texto":"Ransomware não avisa antes de atacar. Quando ele chega, o que importa é a velocidade e a confiabilidade da recuperação."},{"tipo":"paragrafo","texto":"Com o Acronis Cyber Protect, a rede hospitalar passou a contar com proteção integrada e recuperação testada. O time de TI ganhou visibilidade central e a direção, tranquilidade para focar no que importa: o paciente."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '6 min de leitura', '2026-04-15 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'seguranca'), (SELECT id FROM fabricantes WHERE slug = 'acronis'), NULL, now(), now()),
  (gen_random_uuid(), 'FinOps na prática: controlando custos de cloud com Instana e Turbonomic', 'finops-na-pratica-instana-turbonomic', 'WHITEPAPER', 'INTERNO', 'Framework e ferramentas para implementar governança financeira em ambientes multi-cloud.', '[{"tipo":"paragrafo","texto":"FinOps não é uma ferramenta — é uma disciplina que une engenharia, finanças e negócio em torno do valor entregue por cada real gasto em nuvem. Mas a disciplina precisa de instrumentação. É aí que entram observabilidade e automação de recursos."},{"tipo":"subtitulo","texto":"Observabilidade como base da decisão"},{"tipo":"paragrafo","texto":"O IBM Instana entrega visibilidade de ponta a ponta da performance das aplicações, correlacionando consumo de recursos com experiência do usuário. Sem essa visão, qualquer corte de custo é um chute que pode degradar o serviço."},{"tipo":"subtitulo","texto":"Automação de recursos com Turbonomic"},{"tipo":"paragrafo","texto":"O Turbonomic vai além de recomendar: ele equilibra continuamente alocação de CPU, memória e storage para garantir performance ao menor custo possível, aplicando ações de forma automatizada e segura conforme as políticas definidas."},{"tipo":"lista","itens":["Inform: tornar o custo visível e atribuível por time e aplicação.","Optimize: rightsizing contínuo e eliminação de desperdício.","Operate: governança recorrente com metas e accountability."]},{"tipo":"citacao","texto":"Governança financeira de nuvem não nasce de planilha — nasce de dados em tempo real e automação confiável."},{"tipo":"paragrafo","texto":"A Infodive implementa o framework FinOps combinando Instana e Turbonomic, estabelecendo o ciclo de inform, optimize e operate adaptado à realidade multi-cloud de cada cliente."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '8 min de leitura', '2026-04-08 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'observability'), (SELECT id FROM fabricantes WHERE slug = 'ibm'), NULL, now(), now()),
  (gen_random_uuid(), 'IA generativa no ambiente corporativo: por onde começar?', 'ia-generativa-corporativo-por-onde-comecar', 'ARTIGO', 'INTERNO', 'Um guia prático para gestores de TI avaliando a adoção de IA nas operações da empresa.', '[{"tipo":"paragrafo","texto":"A pergunta deixou de ser ''se'' e passou a ser ''como'' adotar IA generativa na empresa. O risco não está em começar tarde, mas em começar sem método — investindo em pilotos vistosos que nunca chegam à produção e não geram valor mensurável."},{"tipo":"subtitulo","texto":"Comece pelo problema, não pela tecnologia"},{"tipo":"paragrafo","texto":"Os melhores casos de uso resolvem dores concretas: atendimento que consome tempo, conhecimento disperso em documentos, processos manuais repetitivos. Escolher um problema bem delimitado e com retorno claro é o que separa um piloto de um produto."},{"tipo":"subtitulo","texto":"Governança e dados desde o primeiro dia"},{"tipo":"paragrafo","texto":"Adotar IA corporativa exige cuidado com privacidade, propriedade dos dados e rastreabilidade das respostas. Plataformas como o watsonx permitem manter o controle sobre onde os dados vivem e como os modelos são governados — requisito inegociável para setores regulados."},{"tipo":"lista","itens":["Defina um caso de uso com ROI mensurável antes de escolher o modelo.","Garanta qualidade e governança dos dados que alimentam a solução.","Mantenha humano no loop nas decisões sensíveis.","Planeje a passagem de piloto para produção desde o início."]},{"tipo":"citacao","texto":"IA generativa no ambiente corporativo não é o futuro — é o presente. O diferencial está na execução disciplinada."},{"tipo":"paragrafo","texto":"A Infodive ajuda a priorizar casos de uso, desenhar a arquitetura e estabelecer a governança necessária para tirar a IA do laboratório e colocá-la para trabalhar."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '7 min de leitura', '2026-04-01 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'inteligencia-artificial'), (SELECT id FROM fabricantes WHERE slug = 'ibm'), NULL, now(), now()),
  (gen_random_uuid(), 'Demo: PowerEdge R760 em workloads de alta disponibilidade', 'demo-dell-poweredge-r760-alta-disponibilidade', 'VIDEO', 'INTERNO', 'Vídeo técnico mostrando configuração e performance em ambiente de produção simulado.', '[{"tipo":"paragrafo","texto":"Neste vídeo técnico, a equipe Infodive coloca o Dell PowerEdge R760 à prova em um cenário de alta disponibilidade, demonstrando configuração, tolerância a falhas e comportamento sob carga em um ambiente de produção simulado."},{"tipo":"subtitulo","texto":"O que você vai ver na demonstração"},{"tipo":"lista","itens":["Configuração de cluster com failover automático.","Comportamento sob carga com simulação de pico de tráfego.","Testes de tolerância a falhas de fonte, disco e rede.","Telemetria e gerenciamento remoto via iDRAC."]},{"tipo":"subtitulo","texto":"Por que o R760 para alta disponibilidade"},{"tipo":"paragrafo","texto":"Com processadores Intel Xeon Scalable, memória DDR5 e ampla expansão NVMe, o PowerEdge R760 entrega a redundância e a performance necessárias para sustentar aplicações críticas com SLA exigente."},{"tipo":"citacao","texto":"Alta disponibilidade não se improvisa: ela é arquitetada, configurada e testada antes de entrar em produção."},{"tipo":"paragrafo","texto":"Quer ver o R760 rodando no seu cenário? A Infodive realiza demonstrações e provas de conceito sob medida. Fale com nosso time para agendar."}]'::jsonb, NULL, NULL, NULL, 'Equipe Infodive', '12 min de vídeo', '2026-03-25 10:00:00', true, false, (SELECT id FROM solucoes WHERE slug = 'infraestrutura'), (SELECT id FROM fabricantes WHERE slug = 'dell'), NULL, now(), now())
ON CONFLICT (slug) DO NOTHING;

