FROM (VALUES
  ('Setor Financeiro', 'Banco Regional', 'Alta disponibilidade para o core bancário', 'Quedas frequentes e gargalos de latência em bancos de dados legados no ambiente crítico.', 'Migração para arquitetura multicloud redundante com telemetria centralizada e failover automático.', '99.98% Uptime', 'Carlos Mendes', 'CTO', 'A Infodive transformou nossa operação crítica e nos deu previsibilidade.', 'https://infodive.com.br/img/cases/banco-regional.jpg', 1),
  ('Varejo e E-commerce', 'Rede Cosmos', 'Proteção de dados e endpoints em escala', 'Falta de visibilidade de ameaças e risco de ransomware nas frentes de caixa.', 'Backup imutável em nuvem com restauração instantânea e 142 endpoints monitorados em tempo integral.', '< 10 min RTO', 'Ana Lima', 'Gerente de TI', 'Visibilidade total e recuperação testada nos pontos de venda.', 'https://infodive.com.br/img/cases/rede-cosmos.jpg', 2),
  ('Indústria Pesada', 'Vesta Manufatura', 'Renovação do parque de processamento', 'Cluster de processamento local defasado gerando gargalos operacionais.', 'Consolidação de 12 servidores antigos em 3 nós de alta densidade com replicação ativa.', '+40% Performance', 'Roberto Khalil', 'Diretor de Operações', 'Ganhamos performance e simplificamos drasticamente o gerenciamento.', 'https://infodive.com.br/img/cases/vesta-manufatura.jpg', 3)
) AS v(segmento, cliente, titulo, desafio, resultado, metrica, autor, cargo, depoimento, imagem_url, ordem)
WHERE NOT EXISTS (SELECT 1 FROM cases);

