INSERT INTO home_problemas (id, titulo, descricao, solucao_indicada, href, ordem, ativo)
SELECT gen_random_uuid(), v.titulo, v.descricao, v.solucao_indicada, v.href, v.ordem, true
FROM (VALUES
  ('Instabilidade e quedas constantes nos sistemas', 'Sistemas indisponíveis durante picos de demanda ou operações sazonais geram prejuízos diretos, desgaste com clientes e arranham a reputação da sua marca.', 'Alta Disponibilidade & Cloud Elástica', '/solucoes', 1),
  ('Backups lentos e vulnerabilidade a ataques cibernéticos', 'Políticas manuais de cópias de dados falham quando mais se precisa. Sua empresa está realmente protegida contra ameaças modernas como ransomware?', 'Backup Imutável & Cibersegurança Ativa', '/solucoes', 2),
  ('Servidores obsoletos gargalando a operação', 'Hardware antigo e sistemas legados limitam a velocidade do seu ERP, gerando atrasos crônicos no faturamento, na entrega e na linha de produção.', 'Modernização de Hardware & Servidores Dedicados', '/solucoes', 3),
  ('Dificuldade na integração e adoção prática de IA', 'Embora a IA seja vital para a competitividade, a falta de expertise técnica e infraestrutura especializada impede que projetos de inteligência saiam do papel.', 'IA Aplicada a Negócios & Modelagem de Dados', '/solucoes', 4),
  ('Complexidade e custos inflados com nuvem híbrida', 'Manter dados confidenciais localmente enquanto se aproveita a flexibilidade da nuvem gera desafios de compliance, latência e custos de nuvem imprevisíveis.', 'Gestão Híbrida & Otimização FinOps', '/solucoes', 5)
) AS v(titulo, descricao, solucao_indicada, href, ordem)
WHERE NOT EXISTS (SELECT 1 FROM home_problemas);

INSERT INTO home_trust_stats (id, eyebrow, prefixo, valor, valor_inicial, sufixo, titulo, descricao, ordem)
