  ('Tradição', 'Desde', 2003, 1990, '', 'História no mercado de TI', 'Consolidando infraestruturas críticas e integrando inovações tecnológicas há mais de duas décadas.', 1),
  ('Confiança', '+', 100, 0, '', 'Clientes ativos e satisfeitos', 'Parcerias sólidas com bancos, hospitais, indústrias e grandes redes varejistas em todo o país.', 2),
