UPDATE home_trust_stats SET eyebrow = 'Sucesso', prefixo = '', valor = 100, sufixo = '%', titulo = 'Projetos entregues com sucesso', descricao = 'Projetos de alta complexidade em nuvem, migração e segurança executados com taxa perfeita de sucesso.', ordem = 3
WHERE eyebrow IN ('Disponibilidade', 'Sucesso') AND sufixo = '%';


INSERT INTO faq (id, pergunta, resposta, ordem, ativo)
SELECT gen_random_uuid(), v.pergunta, v.resposta, v.ordem, true
FROM (VALUES
  ('Que tipos de suporte a Infodive oferece?', 'Oferecemos suporte completo com atendimento NOC 24/7/365 para incidentes críticos, além de suporte comercial e consultivo estruturado em níveis de atendimento (N1, N2 e N3) com acordos de SLA rígidos para garantir a continuidade da sua operação.', 1),
  ('A Infodive atua com migração e sustentação em nuvem (Cloud)?', 'Sim. Auxiliamos empresas no planejamento estratégico, migração segura (seja por decolagem direta ou refatoração de código) e sustentação contínua de infraestruturas em nuvem pública (AWS e Azure), privada e ambientes híbridos.', 2),
  ('Quais são os prazos de resposta (SLA) para chamados críticos?', 'Para incidentes de gravidade crítica (Nível 1), nosso SLA padrão de resposta inicial é de até 15 minutos, monitorado e gerido de ponta a ponta pelo nosso time de NOC especializado.', 3),
  ('Como funciona a parceria com fabricantes como IBM, Dell, Lenovo e Microsoft?', 'Somos parceiros homologados e certificados das principais marcas de tecnologia globais. Isso nos permite desenhar projetos unificados com hardware oficial, licenciamento correto, suporte de fábrica direto e condições comerciais altamente competitivas.', 4),
  ('Os projetos e serviços da Infodive estão em conformidade com a LGPD?', 'Sim, todos os nossos serviços gerenciados, políticas de backup e projetos de segurança de dados seguem estritamente as diretrizes da LGPD (Lei Geral de Proteção de Dados), garantindo total privacidade e conformidade jurídica para o seu negócio.', 5)
) AS v(pergunta, resposta, ordem)
WHERE NOT EXISTS (SELECT 1 FROM faq);

