  '[{"prefixo":"+","valor":500,"sufixo":"","label":"Projetos entregues"},{"prefixo":"","valor":99,"sufixo":"%","label":"Satisfação"}]'::jsonb,
  '[{"icone":"target","titulo":"Foco no resultado","descricao":"Entregamos o que importa."},{"icone":"users","titulo":"Time dedicado","descricao":"Especialistas por projeto."}]'::jsonb, now()
WHERE NOT EXISTS (SELECT 1 FROM servicos_metodologia);

